import React from 'react';
import { Check, Trash2 } from 'lucide-react';

const TodoStep = ({ step, onToggleComplete, onDelete }) => {
  return (
    <div className="flex items-center gap-3 p-2">
      <button
        onClick={() => onToggleComplete(step.id)}
        className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors ${
          step.completed 
            ? 'bg-green-500 border-green-500' 
            : 'border-neutral-400 hover:border-white'
        }`}
      >
        {step.completed && <Check className="w-2.5 h-2.5 text-white" />}
      </button>

      <span className={`text-white flex-1 ${step.completed ? 'line-through opacity-60' : ''}`}>
        {step.description}
      </span>

      <button
        onClick={() => onDelete(step.id)}
        className="text-neutral-500 hover:text-red-500 transition-colors"
      >
        <Trash2 className="w-4 h-4" />
      </button>
    </div>
  );
};

export default TodoStep;
